/**
 * MMS Authentication Service
 *
 * Handles user authentication, JWT token management, and session lifecycle.
 * Uses Bun's native password hashing and Hono's JWT helper.
 *
 * Security features:
 * - bcrypt-compatible password hashing (Bun.password)
 * - JWT access tokens with short expiry (1 hour)
 * - Refresh tokens with longer expiry (7 days)
 * - Session tracking for audit trail
 * - Account lockout after failed attempts
 * - Rate limiting support via failed_login_attempts
 *
 * @see specs/005-api.md Section 5.2 (Authentication Endpoints)
 */

import { eq, and, lt } from 'drizzle-orm';
import { sign, verify, decode } from 'hono/jwt';
import type { JWTPayload } from 'hono/utils/jwt/types';
import { BaseService } from '../lib/services/base';
import { users, sessions } from '../lib/db/schema';
import {
  AuthenticationError,
  TokenExpiredError,
  InvalidTokenError,
} from '../lib/errors';
import { randomUUID } from 'crypto';

// =============================================================================
// Constants
// =============================================================================

const ACCESS_TOKEN_EXPIRY_SECONDS = 3600; // 1 hour
const REFRESH_TOKEN_EXPIRY_SECONDS = 7 * 24 * 3600; // 7 days
const MAX_FAILED_ATTEMPTS = 5;
const LOCKOUT_DURATION_MINUTES = 30;

/** JWT signing algorithm */
const JWT_ALGORITHM = 'HS256' as const;

/**
 * JWT secret - in production, this should come from environment variables
 * or a secrets manager. Using a placeholder that MUST be overridden.
 */
const JWT_SECRET = process.env.JWT_SECRET || 'mms-development-secret-change-in-production';
const REFRESH_TOKEN_SECRET = process.env.REFRESH_TOKEN_SECRET || 'mms-refresh-secret-change-in-production';

// =============================================================================
// Types
// =============================================================================

/** User with role details for authentication response */
export interface AuthenticatedUser {
  id: string;
  email: string;
  displayName: string | null;
  firstName: string | null;
  lastName: string | null;
  roles: string[];
  primaryDepotId: string | null;
}

/** Login request */
export interface LoginRequest {
  email: string;
  password: string;
  ipAddress?: string;
  userAgent?: string;
}

/** Login response */
export interface LoginResponse {
  accessToken: string;
  refreshToken: string;
  expiresIn: number;
  user: AuthenticatedUser;
}

/** Token refresh request */
export interface RefreshRequest {
  refreshToken: string;
  ipAddress?: string;
  userAgent?: string;
}

/** Token refresh response */
export interface RefreshResponse {
  accessToken: string;
  refreshToken: string;
  expiresIn: number;
}

/** JWT payload structure - compatible with Hono's JWTPayload */
export interface JwtPayload extends JWTPayload {
  sub: string;
  email: string;
  roles: string[];
  depotId: string | null;
  sessionId: string;

